#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>

#include "./../main.h"
#include "./../util/avi/avilib.h"
#include "./../util/avi/avimod.h"

// Removed #include "./kernel_gpu_opencl_wrapper.h" to fix missing header error

extern int platform_id_inuse;
extern int device_id_inuse;

void 
kernel_gpu_opencl_wrapper(	params_common common,
							int* endoRow,
							int* endoCol,
							int* tEndoRowLoc,
							int* tEndoColLoc,
							int* epiRow,
							int* epiCol,
							int* tEpiRowLoc,
							int* tEpiColLoc,
							avi_t* frames)
{
#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

	int i;
	int error;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

	// Set CUDA device
	int deviceCount = 0;
	cudaGetDeviceCount(&deviceCount);
	if (deviceCount == 0) {
		fprintf(stderr, "No CUDA devices found\n");
		exit(1);
	}
	int device = 0;
	if (deviceCount > 1) {
		int max_multiprocessors = 0;
		int max_device = 0;
		for (int d = 0; d < deviceCount; d++) {
			cudaDeviceProp prop;
			cudaGetDeviceProperties(&prop, d);
			if (max_multiprocessors < prop.multiProcessorCount) {
				max_multiprocessors = prop.multiProcessorCount;
				max_device = d;
			}
		}
		device = max_device;
	}
	cudaSetDevice(device);

	// Allocate device memory for all buffers
	int allPoints = common.allPoints;
	size_t size_int_endo = common.endo_mem;
	size_t size_int_epi = common.epi_mem;
	size_t size_int_endo_frames = common.endo_mem * common.no_frames;
	size_t size_int_epi_frames = common.epi_mem * common.no_frames;
	size_t size_fp_in_elem = sizeof(fp) * common.in_elem;
	size_t size_fp_in2_elem = sizeof(fp) * common.in2_elem;
	size_t size_fp_conv_elem = sizeof(fp) * common.conv_elem;
	size_t size_fp_in2_pad_cumv_elem = sizeof(fp) * common.in2_pad_cumv_elem;
	size_t size_fp_in2_pad_cumv_sel_elem = sizeof(fp) * common.in2_pad_cumv_sel_elem;
	size_t size_fp_in2_sub_cumh_elem = sizeof(fp) * common.in2_sub_cumh_elem;
	size_t size_fp_in2_sub_cumh_sel_elem = sizeof(fp) * common.in2_sub_cumh_sel_elem;
	size_t size_fp_in2_sub2_elem = sizeof(fp) * common.in2_sub2_elem;
	size_t size_fp_in2_sqr_elem = sizeof(fp) * common.in2_sqr_elem;
	size_t size_fp_in2_sqr_sub2_elem = sizeof(fp) * common.in2_sqr_sub2_elem;
	size_t size_fp_in_sqr_elem = sizeof(fp) * common.in_sqr_elem;
	size_t size_fp_tMask_elem = sizeof(fp) * common.tMask_elem;
	size_t size_fp_mask_conv_elem = sizeof(fp) * common.mask_conv_elem;
	size_t size_fp_in_cols = sizeof(fp) * common.in_cols;
	size_t size_fp_in_sqr_rows = sizeof(fp) * common.in_sqr_rows;
	size_t size_fp_mask_conv_rows = sizeof(fp) * common.mask_conv_rows;
	size_t size_fp_allPoints = sizeof(fp) * allPoints;
	size_t size_int_mask_conv_rows = sizeof(int) * common.mask_conv_rows * allPoints;
	size_t size_fp_checksum = sizeof(fp) * CHECK;

	fp* d_frame;
	int* d_endoRow;
	int* d_endoCol;
	int* d_tEndoRowLoc;
	int* d_tEndoColLoc;
	int* d_epiRow;
	int* d_epiCol;
	int* d_tEpiRowLoc;
	int* d_tEpiColLoc;
	fp* d_endoT;
	fp* d_epiT;
	fp* d_in2_all;
	fp* d_conv_all;
	fp* d_in2_pad_cumv_all;
	fp* d_in2_pad_cumv_sel_all;
	fp* d_in2_sub_cumh_all;
	fp* d_in2_sub_cumh_sel_all;
	fp* d_in2_sub2_all;
	fp* d_in2_sqr_all;
	fp* d_in2_sqr_sub2_all;
	fp* d_in_sqr_all;
	fp* d_tMask_all;
	fp* d_mask_conv_all;
	fp* d_in_mod_temp_all;
	fp* in_partial_sum_all;
	fp* in_sqr_partial_sum_all;
	fp* par_max_val_all;
	int* par_max_coo_all;
	fp* in_final_sum_all;
	fp* in_sqr_final_sum_all;
	fp* denomT_all;
	fp* d_checksum;

	cudaMalloc((void**)&d_frame, common.frame_mem);
	cudaMalloc((void**)&d_endoRow, size_int_endo);
	cudaMalloc((void**)&d_endoCol, size_int_endo);
	cudaMalloc((void**)&d_tEndoRowLoc, size_int_endo_frames);
	cudaMalloc((void**)&d_tEndoColLoc, size_int_endo_frames);
	cudaMalloc((void**)&d_epiRow, size_int_epi);
	cudaMalloc((void**)&d_epiCol, size_int_epi);
	cudaMalloc((void**)&d_tEpiRowLoc, size_int_epi_frames);
	cudaMalloc((void**)&d_tEpiColLoc, size_int_epi_frames);
	cudaMalloc((void**)&d_endoT, size_fp_in_elem * common.endoPoints);
	cudaMalloc((void**)&d_epiT, size_fp_in_elem * common.epiPoints);
	cudaMalloc((void**)&d_in2_all, size_fp_in2_elem * allPoints);
	cudaMalloc((void**)&d_conv_all, size_fp_conv_elem * allPoints);
	cudaMalloc((void**)&d_in2_pad_cumv_all, size_fp_in2_pad_cumv_elem * allPoints);
	cudaMalloc((void**)&d_in2_pad_cumv_sel_all, size_fp_in2_pad_cumv_sel_elem * allPoints);
	cudaMalloc((void**)&d_in2_sub_cumh_all, size_fp_in2_sub_cumh_elem * allPoints);
	cudaMalloc((void**)&d_in2_sub_cumh_sel_all, size_fp_in2_sub_cumh_sel_elem * allPoints);
	cudaMalloc((void**)&d_in2_sub2_all, size_fp_in2_sub2_elem * allPoints);
	cudaMalloc((void**)&d_in2_sqr_all, size_fp_in2_sqr_elem * allPoints);
	cudaMalloc((void**)&d_in2_sqr_sub2_all, size_fp_in2_sqr_sub2_elem * allPoints);
	cudaMalloc((void**)&d_in_sqr_all, size_fp_in_sqr_elem * allPoints);
	cudaMalloc((void**)&d_tMask_all, size_fp_tMask_elem * allPoints);
	cudaMalloc((void**)&d_mask_conv_all, size_fp_mask_conv_elem * allPoints);
	cudaMalloc((void**)&d_in_mod_temp_all, sizeof(fp) * common.in_elem * allPoints);
	cudaMalloc((void**)&in_partial_sum_all, size_fp_in_cols * allPoints);
	cudaMalloc((void**)&in_sqr_partial_sum_all, size_fp_in_sqr_rows * allPoints);
	cudaMalloc((void**)&par_max_val_all, size_fp_mask_conv_rows * allPoints);
	cudaMalloc((void**)&par_max_coo_all, size_int_mask_conv_rows);
	cudaMalloc((void**)&in_final_sum_all, size_fp_allPoints);
	cudaMalloc((void**)&in_sqr_final_sum_all, size_fp_allPoints);
	cudaMalloc((void**)&denomT_all, size_fp_allPoints);
	cudaMalloc((void**)&d_checksum, size_fp_checksum);

	// Copy input data to device
	cudaMemcpy(d_endoRow, endoRow, size_int_endo, cudaMemcpyHostToDevice);
	cudaMemcpy(d_endoCol, endoCol, size_int_endo, cudaMemcpyHostToDevice);
	cudaMemcpy(d_epiRow, epiRow, size_int_epi, cudaMemcpyHostToDevice);
	cudaMemcpy(d_epiCol, epiCol, size_int_epi, cudaMemcpyHostToDevice);

	// Setup kernel launch parameters
	dim3 blockDim(NUMBER_THREADS);
	dim3 gridDim(common.allPoints);

	printf("# of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n", (int)gridDim.x, (int)blockDim.x);

	// Loop over frames
	printf("frame progress: ");
	fflush(NULL);

	for(int frame_no=0; frame_no<common.frames_processed; frame_no++){

		// Get frame data from AVI
		fp* frame = get_frame(frames, frame_no, 0, 0, 1);
		if (!frame) {
			fprintf(stderr, "Failed to get frame %d\n", frame_no);
			exit(1);
		}

		// Copy frame data to device
		cudaMemcpy(d_frame, frame, common.frame_mem, cudaMemcpyHostToDevice);

		// Launch kernel
		kernel_gpu_opencl<<<gridDim, blockDim>>>(common,
			d_frame,
			frame_no,
			d_endoRow,
			d_endoCol,
			d_tEndoRowLoc,
			d_tEndoColLoc,
			d_epiRow,
			d_epiCol,
			d_tEpiRowLoc,
			d_tEpiColLoc,
			d_endoT,
			d_epiT,
			d_in2_all,
			d_conv_all,
			d_in2_pad_cumv_all,
			d_in2_pad_cumv_sel_all,
			d_in2_sub_cumh_all,
			d_in2_sub_cumh_sel_all,
			d_in2_sub2_all,
			d_in2_sqr_all,
			d_in2_sqr_sub2_all,
			d_in_sqr_all,
			d_tMask_all,
			d_mask_conv_all,
			d_in_mod_temp_all,
			in_partial_sum_all,
			in_sqr_partial_sum_all,
			par_max_val_all,
			par_max_coo_all,
			in_final_sum_all,
			in_sqr_final_sum_all,
			denomT_all,
			d_checksum);

		cudaDeviceSynchronize();

		free(frame);

		printf("%d ", frame_no);
		fflush(NULL);

#ifdef TEST_CHECKSUM
		fp* checksum = (fp*)malloc(sizeof(fp) * CHECK);
		cudaMemcpy(checksum, d_checksum, sizeof(fp)*CHECK, cudaMemcpyDeviceToHost);
		printf("CHECKSUM:\n");
		for(i=0; i<CHECK; i++){
			printf("%f ", checksum[i]);
		}
		printf("\n\n");
		free(checksum);
#endif

	}

	printf("\n");
	fflush(NULL);

	// Copy results back to host
	cudaMemcpy(tEndoRowLoc, d_tEndoRowLoc, size_int_endo_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEndoColLoc, d_tEndoColLoc, size_int_endo_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEpiRowLoc, d_tEpiRowLoc, size_int_epi_frames, cudaMemcpyDeviceToHost);
	cudaMemcpy(tEpiColLoc, d_tEpiColLoc, size_int_epi_frames, cudaMemcpyDeviceToHost);

#ifdef TEST_OUTPUT
	for(i=0; i<common.frames_processed; i++){
		printf("%d: ", i);
		for(int j=0; j<common.endoPoints; j++){
			printf("%d ", tEndoRowLoc[j*common.no_frames+i]);
		}
		printf("\n\n");
	}
#endif

	// Free device memory
	cudaFree(d_frame);
	cudaFree(d_endoRow);
	cudaFree(d_endoCol);
	cudaFree(d_tEndoRowLoc);
	cudaFree(d_tEndoColLoc);
	cudaFree(d_epiRow);
	cudaFree(d_epiCol);
	cudaFree(d_tEpiRowLoc);
	cudaFree(d_tEpiColLoc);
	cudaFree(d_endoT);
	cudaFree(d_epiT);
	cudaFree(d_in2_all);
	cudaFree(d_conv_all);
	cudaFree(d_in2_pad_cumv_all);
	cudaFree(d_in2_pad_cumv_sel_all);
	cudaFree(d_in2_sub_cumh_all);
	cudaFree(d_in2_sub_cumh_sel_all);
	cudaFree(d_in2_sub2_all);
	cudaFree(d_in2_sqr_all);
	cudaFree(d_in2_sqr_sub2_all);
	cudaFree(d_in_sqr_all);
	cudaFree(d_tMask_all);
	cudaFree(d_mask_conv_all);
	cudaFree(d_in_mod_temp_all);
	cudaFree(in_partial_sum_all);
	cudaFree(in_sqr_partial_sum_all);
	cudaFree(par_max_val_all);
	cudaFree(par_max_coo_all);
	cudaFree(in_final_sum_all);
	cudaFree(in_sqr_final_sum_all);
	cudaFree(denomT_all);
	cudaFree(d_checksum);

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
	tvsub(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

	printf("Time spent in different stages of the application:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}
